package com.ecommerce.search.service;

import com.ecommerce.search.dto.BulkIndexResponse;
import com.ecommerce.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.delete.DeleteResponse;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.action.update.UpdateResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.UUID;

@Slf4j
@Service
@RequiredArgsConstructor
public class ProductIndexingService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    private ObjectMapper getMapper() {
        ObjectMapper mapper = new ObjectMapper();
        mapper.registerModule(new JavaTimeModule());
        return mapper;
    }

    public String indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isEmpty()) {
            product.setId(UUID.randomUUID().toString());
        }
        if (product.getCreatedAt() == null) {
            product.setCreatedAt(LocalDateTime.now());
        }
        product.setUpdatedAt(LocalDateTime.now());

        ObjectMapper mapper = getMapper();
        String jsonString = mapper.writeValueAsString(product);

        IndexRequest request = new IndexRequest(IndexManagementService.PRODUCTS_INDEX)
                .id(product.getId())
                .source(jsonString, XContentType.JSON);

        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        log.info("Product indexed: id={}, result={}", product.getId(), response.getResult().name());
        return product.getId();
    }

    public Product getProduct(String productId) throws IOException {
        GetRequest request = new GetRequest(IndexManagementService.PRODUCTS_INDEX, productId);
        GetResponse response = client.get(request, RequestOptions.DEFAULT);

        if (response.isExists()) {
            ObjectMapper mapper = getMapper();
            Product product = mapper.readValue(response.getSourceAsString(), Product.class);
            product.setId(response.getId());
            return product;
        }
        return null;
    }

    public String updateProduct(String productId, Product product) throws IOException {
        product.setId(productId);
        product.setUpdatedAt(LocalDateTime.now());

        ObjectMapper mapper = getMapper();
        String jsonString = mapper.writeValueAsString(product);

        UpdateRequest request = new UpdateRequest(IndexManagementService.PRODUCTS_INDEX, productId)
                .doc(jsonString, XContentType.JSON)
                .docAsUpsert(true);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        log.info("Product updated: id={}, result={}", productId, response.getResult().name());
        return productId;
    }

    public String partialUpdateProduct(String productId, Map<String, Object> fields) throws IOException {
        fields.put("updatedAt", LocalDateTime.now().toString());

        UpdateRequest request = new UpdateRequest(IndexManagementService.PRODUCTS_INDEX, productId)
                .doc(fields);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        log.info("Product partially updated: id={}, result={}", productId, response.getResult().name());
        return productId;
    }

    public boolean deleteProduct(String productId) throws IOException {
        DeleteRequest request = new DeleteRequest(IndexManagementService.PRODUCTS_INDEX, productId);
        DeleteResponse response = client.delete(request, RequestOptions.DEFAULT);
        log.info("Product deleted: id={}, result={}", productId, response.getResult().name());
        return response.getResult().name().equals("DELETED");
    }

    public BulkIndexResponse bulkIndexProducts(List<Product> products) throws IOException {
        long startTime = System.currentTimeMillis();
        BulkRequest bulkRequest = new BulkRequest();
        ObjectMapper mapper = getMapper();

        for (Product product : products) {
            if (product.getId() == null || product.getId().isEmpty()) {
                product.setId(UUID.randomUUID().toString());
            }
            if (product.getCreatedAt() == null) {
                product.setCreatedAt(LocalDateTime.now());
            }
            product.setUpdatedAt(LocalDateTime.now());

            String jsonString = mapper.writeValueAsString(product);
            IndexRequest indexRequest = new IndexRequest(IndexManagementService.PRODUCTS_INDEX)
                    .id(product.getId())
                    .source(jsonString, XContentType.JSON);
            bulkRequest.add(indexRequest);
        }

        BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        long timeTaken = System.currentTimeMillis() - startTime;

        List<String> errors = new ArrayList<>();
        int failureCount = 0;

        if (bulkResponse.hasFailures()) {
            bulkResponse.forEach(item -> {
                if (item.isFailed()) {
                    errors.add(String.format("Item %s failed: %s", item.getId(), item.getFailureMessage()));
                }
            });
            failureCount = errors.size();
        }

        BulkIndexResponse response = BulkIndexResponse.builder()
                .totalProcessed(products.size())
                .successCount(products.size() - failureCount)
                .failureCount(failureCount)
                .errors(errors)
                .timeTakenMs(timeTaken)
                .build();

        log.info("Bulk indexing completed: total={}, success={}, failures={}, time={}ms",
                response.getTotalProcessed(), response.getSuccessCount(),
                response.getFailureCount(), response.getTimeTakenMs());

        return response;
    }

    public BulkIndexResponse bulkDeleteProducts(List<String> productIds) throws IOException {
        long startTime = System.currentTimeMillis();
        BulkRequest bulkRequest = new BulkRequest();

        for (String id : productIds) {
            DeleteRequest deleteRequest = new DeleteRequest(IndexManagementService.PRODUCTS_INDEX, id);
            bulkRequest.add(deleteRequest);
        }

        BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        long timeTaken = System.currentTimeMillis() - startTime;

        List<String> errors = new ArrayList<>();
        int failureCount = 0;

        if (bulkResponse.hasFailures()) {
            bulkResponse.forEach(item -> {
                if (item.isFailed()) {
                    errors.add(String.format("Item %s failed: %s", item.getId(), item.getFailureMessage()));
                }
            });
            failureCount = errors.size();
        }

        return BulkIndexResponse.builder()
                .totalProcessed(productIds.size())
                .successCount(productIds.size() - failureCount)
                .failureCount(failureCount)
                .errors(errors)
                .timeTakenMs(timeTaken)
                .build();
    }
}

