import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final SearchQueryService searchQueryService;

    private ObjectMapper getMapper() {
        ObjectMapper mapper = new ObjectMapper();
        mapper.registerModule(new JavaTimeModule());
        return mapper;
    }

    public SearchResponse search(SearchRequest searchRequest) throws IOException {
        long startTime = System.currentTimeMillis();

        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCTS_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = buildQuery(searchRequest);
        sourceBuilder.query(boolQuery);

        addSorting(sourceBuilder, searchRequest);
        addPagination(sourceBuilder, searchRequest);
        addHighlighting(sourceBuilder);
        addAggregations(sourceBuilder);

        esRequest.source(sourceBuilder);

        EsSearchResponse esResponse = client.search(esRequest, RequestOptions.DEFAULT);
        long responseTime = System.currentTimeMillis() - startTime;

        SearchResponse response = buildSearchResponse(esResponse, searchRequest, responseTime);

        // Log search query asynchronously
        searchQueryService.logSearchQuery(searchRequest, response, responseTime);

        return response;
    }

    private BoolQueryBuilder buildQuery(SearchRequest searchRequest) {
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Full-text search
        if (searchRequest.getQuery() != null && !searchRequest.getQuery().trim().isEmpty()) {
            MultiMatchQueryBuilder multiMatch = QueryBuilders.multiMatchQuery(searchRequest.getQuery(),
                            "name^3", "description^1", "brand^2", "category^2", "tags^1.5")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness("AUTO")
                    .prefixLength(2)
                    .minimumShouldMatch("75%");
            boolQuery.must(multiMatch);
        }

        // Category filter
        if (searchRequest.getCategory() != null && !searchRequest.getCategory().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("category.keyword", searchRequest.getCategory()));
        }

        // Brand filter
        if (searchRequest.getBrands() != null && !searchRequest.getBrands().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", searchRequest.getBrands()));
        }

        // Price range filter
        if (searchRequest.getMinPrice() != null || searchRequest.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (searchRequest.getMinPrice() != null) {
                rangeQuery.gte(searchRequest.getMinPrice());
            }
            if (searchRequest.getMaxPrice() != null) {
                rangeQuery.lte(searchRequest.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        // Rating filter
        if (searchRequest.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("rating").gte(searchRequest.getMinRating()));
        }

        // In stock filter
        if (searchRequest.getInStock() != null && searchRequest.getInStock()) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", true));
        }

        // Tags filter
        if (searchRequest.getTags() != null && !searchRequest.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", searchRequest.getTags()));
        }

        // Seller filter
        if (searchRequest.getSeller() != null && !searchRequest.getSeller().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("seller.keyword", searchRequest.getSeller()));
        }

        // Attribute filters
        if (searchRequest.getAttributes() != null && !searchRequest.getAttributes().isEmpty()) {
            searchRequest.getAttributes().forEach((key, value) -> {
                boolQuery.filter(QueryBuilders.termQuery("attributes." + key + ".keyword", value));
            });
        }

        return boolQuery;
    }

    private void addSorting(SearchSourceBuilder sourceBuilder, SearchRequest searchRequest) {
        String sortBy = searchRequest.getSortBy();
        SortOrder sortOrder = "asc".equalsIgnoreCase(searchRequest.getSortOrder()) ? SortOrder.ASC : SortOrder.DESC;

        switch (sortBy != null ? sortBy.toLowerCase() : "relevance") {
            case "price":
                sourceBuilder.sort(SortBuilders.fieldSort("price").order(sortOrder));
                break;
            case "rating":
                sourceBuilder.sort(SortBuilders.fieldSort("rating").order(sortOrder));
                break;
            case "name":
                sourceBuilder.sort(SortBuilders.fieldSort("name.keyword").order(sortOrder));
                break;
            case "newest":
                sourceBuilder.sort(SortBuilders.fieldSort("createdAt").order(SortOrder.DESC));
                break;
            case "popularity":
                sourceBuilder.sort(SortBuilders.fieldSort("reviewCount").order(SortOrder.DESC));
                break;
            case "relevance":
            default:
                sourceBuilder.sort(SortBuilders.scoreSort().order(SortOrder.DESC));
                break;
        }
    }

    private void addPagination(SearchSourceBuilder sourceBuilder, SearchRequest searchRequest) {
        int page = Math.max(0, searchRequest.getPage());
        int size = Math.min(Math.max(1, searchRequest.getSize()), 100);
        sourceBuilder.from(page * size);
        sourceBuilder.size(size);
    }

    private void addHighlighting(SearchSourceBuilder sourceBuilder) {
        HighlightBuilder highlightBuilder = new HighlightBuilder();
        highlightBuilder.field(new HighlightBuilder.Field("name").preTags("<em>").postTags("</em>"));
        highlightBuilder.field(new HighlightBuilder.Field("description").preTags("<em>").postTags("</em>")
                .fragmentSize(150).numberOfFragments(3));
        sourceBuilder.highlighter(highlightBuilder);
    }

    private void addAggregations(SearchSourceBuilder sourceBuilder) {
        // Brand facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("brands")
                        .field("brand.keyword")
                        .size(50)
        );

        // Category facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("categories")
                        .field("category.keyword")
                        .size(50)
        );

        // Price ranges facet
        RangeAggregationBuilder priceRanges = AggregationBuilders.range("price_ranges")
                .field("price")
                .addUnboundedTo("Under $25", 25)
                .addRange("$25 - $50", 25, 50)
                .addRange("$50 - $100", 50, 100)
                .addRange("$100 - $200", 100, 200)
                .addRange("$200 - $500", 200, 500)
                .addUnboundedFrom("$500+", 500);
        sourceBuilder.aggregation(priceRanges);

        // Rating facet
        sourceBuilder.aggregation(
                AggregationBuilders.range("ratings")
                        .field("rating")
                        .addRange("4+ Stars", 4, 5.01)
                        .addRange("3+ Stars", 3, 5.01)
                        .addRange("2+ Stars", 2, 5.01)
                        .addRange("1+ Stars", 1, 5.01)
        );

        // Tags facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("tags")
                        .field("tags")
                        .size(30)
        );

        // Seller facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("sellers")
                        .field("seller.keyword")
                        .size(20)
        );

        // In stock count
        sourceBuilder.aggregation(
                AggregationBuilders.terms("availability")
                        .field("inStock")
        );
    }

    private SearchResponse buildSearchResponse(EsSearchResponse esResponse, SearchRequest searchRequest, long responseTime) throws IOException {
        ObjectMapper mapper = getMapper();
        List<Product> products = new ArrayList<>();

        for (SearchHit hit : esResponse.getHits().getHits()) {
            Product product = mapper.readValue(hit.getSourceAsString(), Product.class);
            product.setId(hit.getId());

            // Apply highlights
            Map<String, HighlightField> highlightFields = hit.getHighlightFields();
            if (highlightFields.containsKey("name")) {
                String highlightedName = Arrays.stream(highlightFields.get("name").getFragments())
                        .map(Text::string)
                        .collect(Collectors.joining(" "));
                product.setName(highlightedName);
            }

            products.add(product);
        }

        long totalHits = esResponse.getHits().getTotalHits().value;
        int totalPages = (int) Math.ceil((double) totalHits / searchRequest.getSize());

        Map<String, List<SearchResponse.FacetEntry>> facets = extractFacets(esResponse);

        return SearchResponse.builder()
                .products(products)
                .totalHits(totalHits)
                .page(searchRequest.getPage())
                .size(searchRequest.getSize())
                .totalPages(totalPages)
                .responseTimeMs(responseTime)
                .facets(facets)
                .build();
    }

    private Map<String, List<SearchResponse.FacetEntry>> extractFacets(EsSearchResponse esResponse) {
        Map<String, List<SearchResponse.FacetEntry>> facets = new HashMap<>();

        if (esResponse.getAggregations() == null) return facets;

        // Extract terms aggregations
        String[] termsAggs = {"brands", "categories", "tags", "sellers", "availability"};
        for (String aggName : termsAggs) {
            try {
                Terms terms = esResponse.getAggregations().get(aggName);
                if (terms != null) {
                    List<SearchResponse.FacetEntry> entries = terms.getBuckets().stream()
                            .map(bucket -> SearchResponse.FacetEntry.builder()
                                    .key(bucket.getKeyAsString())
                                    .count(bucket.getDocCount())
                                    .build())
                            .collect(Collectors.toList());
                    facets.put(aggName, entries);
                }
            } catch (Exception e) {
                log.debug("Could not extract aggregation: {}", aggName);
            }
        }

        // Extract range aggregations
        String[] rangeAggs = {"price_ranges", "ratings"};
        for (String aggName : rangeAggs) {
            try {
                Range range = esResponse.getAggregations().get(aggName);
                if (range != null) {
                    List<SearchResponse.FacetEntry> entries = range.getBuckets().stream()
                            .filter(bucket -> bucket.getDocCount() > 0)
                            .map(bucket -> SearchResponse.FacetEntry.builder()
                                    .key(bucket.getKeyAsString())
                                    .count(bucket.getDocCount())
                                    .build())
                            .collect(Collectors.toList());
                    facets.put(aggName, entries);
                }
            } catch (Exception e) {
                log.debug("Could not extract range aggregation: {}", aggName);
            }
        }

        return facets;
    }

    public AutocompleteResponse autocomplete(String prefix, int maxSuggestions) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCTS_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery()
                .should(QueryBuilders.matchPhrasePrefixQuery("name", prefix).boost(3.0f))
                .should(QueryBuilders.matchPhrasePrefixQuery("brand", prefix).boost(2.0f))
                .should(QueryBuilders.matchQuery("name.autocomplete", prefix))
                .minimumShouldMatch(1);

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(maxSuggestions);
        sourceBuilder.fetchSource(new String[]{"name", "category", "imageUrl", "price", "id"}, null);

        esRequest.source(sourceBuilder);

        EsSearchResponse esResponse = client.search(esRequest, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        List<AutocompleteResponse.ProductSuggestion> productSuggestions = new ArrayList<>();

        ObjectMapper mapper = getMapper();
        for (SearchHit hit : esResponse.getHits().getHits()) {
            Map<String, Object> source = hit.getSourceAsMap();
            String name = (String) source.get("name");
            suggestions.add(name);

            productSuggestions.add(AutocompleteResponse.ProductSuggestion.builder()
                    .id(hit.getId())
                    .name(name)
                    .category((String) source.get("category"))
                    .imageUrl((String) source.get("imageUrl"))
                    .price(source.get("price") != null ? ((Number) source.get("price")).doubleValue() : null)
                    .build());
        }

        return AutocompleteResponse.builder()
                .suggestions(suggestions)
                .productSuggestions(productSuggestions)
                .build();
    }

    public List<Product> findSimilarProducts(String productId, int maxResults) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCTS_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.moreLikeThisQuery(
                        new String[]{"name", "description", "category", "tags"},
                        null,
                        new org.elasticsearch.index.query.MoreLikeThisQueryBuilder.Item[]{
                                new org.elasticsearch.index.query.MoreLikeThisQueryBuilder.Item(
                                        IndexManagementService.PRODUCTS_INDEX, productId)
                        })
                .minTermFreq(1)
                .minDocFreq(1)
                .maxQueryTerms(12));

        sourceBuilder.size(maxResults);
        esRequest.source(sourceBuilder);

        EsSearchResponse esResponse = client.search(esRequest, RequestOptions.DEFAULT);

        ObjectMapper mapper = getMapper();
        List<Product> products = new ArrayList<>();
        for (SearchHit hit : esResponse.getHits().getHits()) {
            if (!hit.getId().equals(productId)) {
                Product product = mapper.readValue(hit.getSourceAsString(), Product.class);
                product.setId(hit.getId());
                products.add(product);
            }
        }
        return products;
    }

    public SearchResponse searchByCategory(String category, int page, int size) throws IOException {
        SearchRequest searchRequest = SearchRequest.builder()
                .category(category)
                .page(page)
                .size(size)
                .sortBy("popularity")
                .build();
        return search(searchRequest);
    }

    public SearchResponse searchByBrand(String brand, int page, int size) throws IOException {
        SearchRequest searchRequest = SearchRequest.builder()
                .brands(List.of(brand))
                .page(page)
                .size(size)
                .sortBy("popularity")
                .build();
        return search(searchRequest);
    }
}

