package com.ecommerce.search.controller;

import com.ecommerce.search.dto.BulkIndexResponse;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexingService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;
import java.util.Map;

@Slf4j
@RestController
@RequestMapping("/api/products")
@RequiredArgsConstructor
public class ProductController {

    private final ProductIndexingService productIndexingService;

    @PostMapping
    public ResponseEntity<Map<String, String>> indexProduct(@RequestBody Product product) {
        try {
            String id = productIndexingService.indexProduct(product);
            return ResponseEntity.status(HttpStatus.CREATED)
                    .body(Map.of("id", id, "message", "Product indexed successfully"));
        } catch (IOException e) {
            log.error("Failed to index product", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("error", "Failed to index product: " + e.getMessage()));
        }
    }

    @GetMapping("/{id}")
    public ResponseEntity<?> getProduct(@PathVariable String id) {
        try {
            Product product = productIndexingService.getProduct(id);
            if (product == null) {
                return ResponseEntity.notFound().build();
            }
            return ResponseEntity.ok(product);
        } catch (IOException e) {
            log.error("Failed to get product: {}", id, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("error", "Failed to get product: " + e.getMessage()));
        }
    }

    @PutMapping("/{id}")
    public ResponseEntity<Map<String, String>> updateProduct(@PathVariable String id, @RequestBody Product product) {
        try {
            productIndexingService.updateProduct(id, product);
            return ResponseEntity.ok(Map.of("id", id, "message", "Product updated successfully"));
        } catch (IOException e) {
            log.error("Failed to update product: {}", id, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("error", "Failed to update product: " + e.getMessage()));
        }
    }

    @PatchMapping("/{id}")
    public ResponseEntity<Map<String, String>> partialUpdateProduct(@PathVariable String id,
                                                                     @RequestBody Map<String, Object> fields) {
        try {
            productIndexingService.partialUpdateProduct(id, fields);
            return ResponseEntity.ok(Map.of("id", id, "message", "Product partially updated successfully"));
        } catch (IOException e) {
            log.error("Failed to partially update product: {}", id, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("error", "Failed to update product: " + e.getMessage()));
        }
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Map<String, String>> deleteProduct(@PathVariable String id) {
        try {
            boolean deleted = productIndexingService.deleteProduct(id);
            if (deleted) {
                return ResponseEntity.ok(Map.of("id", id, "message", "Product deleted successfully"));
            }
            return ResponseEntity.notFound().build();
        } catch (IOException e) {
            log.error("Failed to delete product: {}", id, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("error", "Failed to delete product: " + e.getMessage()));
        }
    }

    @PostMapping("/bulk")
    public ResponseEntity<BulkIndexResponse> bulkIndexProducts(@RequestBody List<Product> products) {
        try {
            BulkIndexResponse response = productIndexingService.bulkIndexProducts(products);
            return ResponseEntity.ok(response);
        } catch (IOException e) {
            log.error("Failed to bulk index products", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(BulkIndexResponse.builder()
                            .errors(List.of(e.getMessage()))
                            .build());
        }
    }

    @DeleteMapping("/bulk")
    public ResponseEntity<BulkIndexResponse> bulkDeleteProducts(@RequestBody List<String> productIds) {
        try {
            BulkIndexResponse response = productIndexingService.bulkDeleteProducts(productIds);
            return ResponseEntity.ok(response);
        } catch (IOException e) {
            log.error("Failed to bulk delete products", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(BulkIndexResponse.builder()
                            .errors(List.of(e.getMessage()))
                            .build());
        }
    }
}

